class Solution(object):
    def addOperators(self, num, target):
        """
        :type num: str
        :type target: int
        :rtype: List[str]
        """
        self.res = []

        def dfs(s, cur_val, pre_op, path):
            if not s:
                if cur_val == target:
                    self.res.append(path)
                return

            for i in range(1, len(s) + 1):
                if i > 1 and s[0] == '0':
                    continue

                cur_num = int(s[:i])

                # Add operation
                dfs(s[i:], cur_val + cur_num, '+', path + '+' + str(cur_num))

                # Subtract operation
                dfs(s[i:], cur_val - cur_num, '-', path + '-' + str(cur_num))

                # Multiply operation
                if pre_op == '+':
                    dfs(s[i:], cur_val * cur_num, '*', path + '*' + str(cur_num))
                elif pre_op == '-':
                    dfs(s[i:], (cur_val - pre_op * cur_num), '*', path + '*' + str(cur_num))

        dfs(num, 0, None, '')

        return self.res

