def maxNumber(nums1, nums2, k):
    # Use a stack to keep track of the largest possible numbers with k digits
    stack = []

    for num in nums1:
        while stack and len(stack) < k and num > stack[-1]:
            stack.pop()
        stack.append(num)

    # Take at most k elements from the remaining elements in nums2
    for _ in range(k - len(stack)):
        if nums2 and (not stack or nums2[-1] >= stack[-1]):
            stack.append(nums2.pop())

    return stack[:k]

