from bisect import bisect_left

def smallest_distance_pair(nums, k):
    nums.sort()
    n = len(nums)

    def count_smaller_than(target):
        count = 0
        for i in range(n):
            index = bisect_left(nums, target + nums[i])
            if index != n:
                count += index - i
        return count

    left, right = 0, nums[-1] - nums[0]
    while left < right:
        mid = (left + right) // 2
        if count_smaller_than(mid) >= k:
            right = mid
        else:
            left = mid + 1
    return left

