class Solution(object):
    def buildTree(self, inorder, postorder):
        """
        :type inorder: List[int]
        :type postorder: List[int]
        :rtype: TreeNode
        """
        # Helper function to find the index of an element in the inorder array
        def findIndex(arr, x):
            for i in range(len(arr)):
                if arr[i] == x:
                    return i

        # Recursive function to build the tree
        def build(inorder, postorder, start, end):
            if start > end:
                return None

            root_val = postorder.pop()
            root = TreeNode(root_val)

            root_index = findIndex(inorder, root_val)

            root.left = build(inorder, postorder, start, root_index - 1)
            root.right = build(inorder, postorder, root_index + 1, end)

            return root

        # Start building the tree from the entire inorder and postorder arrays
        return build(inorder, postorder, 0, len(inorder) - 1)

