        """
        :type root: TreeNode
        :rtype: bool
        """

        # Helper function to check if a given node and its subtree satisfy the BST property
        def validate(node, lower=float('-inf'), upper=float('inf')):
            # If the current node is None, it is considered a valid BST
            if not node:
                return True

            # Check if the current node's value is within the valid range
            if node.val <= lower or node.val >= upper:
                return False

            # Recursively check the left and right subtrees
