class Solution(object):
    def uniquePaths(self, m, n):
        """
        :type m: int
        :type n: int
        :rtype: int
        """
        if m == 1 or n == 1:
            return 1

        # Create a 2D array to store the number of ways to reach each cell
        dp = [[0 for _ in range(n)] for _ in range(m)]

        # There's one way to reach any cell in the first row and column
        for i in range(m):
            dp[i][0] = 1
        for j in range(n):
            dp[0][j] = 1

        # Fill the DP table
        for i in range(1, m):
            for j in range(1, n):
                dp[i][j] = dp[i-1][j] + dp[i][j-1]

        # The number of ways to reach the bottom-right corner is stored in dp[m-1][n-1]
        return dp[m-1][n-1]

