class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        # Step 1: Use BFS to find all valid parentheses combinations.
        queue = deque([(s, 0)])
        visited = set()
        while queue:
            current_str, depth = queue.popleft()
            if self.isValid(current_str):
                return [current_str]  # Return the first valid string found.

            for i in range(len(current_str)):
                new_str = current_str[:i] + current_str[i+1:]
                if new_str not in visited:
                    visited.add(new_str)
                    queue.append((new_str, depth + 1))

        # Step 2: If no valid parentheses are found, return an empty list.
        return []

    def isValid(self, s):
        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            elif char == ')':
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

