        cols = len(isInfected[0])
        total_walls = 0

        while True:
            # Step 1: Find all infected regions
            infected_regions = []
            for i in range(rows):
                for j in range(cols):
                    if isInfected[i][j] == 1:
                        infected_region = self.find_infected_region(i, j, isInfected)
                        if infected_region:
                            infected_regions.append(infected_region)

            # Step 2: Sort infected regions by size (largest first)
            infected_regions.sort(key=lambda x: len(x), reverse=True)

            # Step 3: Process the largest infected region
            if not infected_regions:
                break

            # Step 4: Add walls to the largest infected region
            walls_to_add = self.add_walls_to_region(infected_regions[0], isInfected)
            total_walls += walls_to_add

            # Step 5: Update isInfected grid
            self.update_isInfected_grid(isInfected, infected_regions[0])

            # Step 6: Remove visited cells from the queue
            self.remove_visited_cells(isInfected)

        return total_walls

    def find_infected_region(self, x, y, isInfected):
        queue = deque([(x, y)])
        visited = set((x, y))
        region = [(x, y)]

        while queue:
            current_x, current_y = queue.popleft()

            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                new_x, new_y = current_x + dx, current_y + dy

                if 0 <= new_x < rows and 0 <= new_y < cols and isInfected[new_x][new_y] == 1 and (new_x, new_y) not in visited:
                    visited.add((new_x, new_y))
                    region.append((new_x, new_y))
                    queue.append((new_x, new_y))

        return region

    def add_walls_to_region(self, region, isInfected):
        walls_to_add = 0

        for x, y in region:
            if x > 0 and isInfected[x-1][y] == 0:
                isInfected[x-1][y] = 2
                walls_to_add += 1
            if x < rows - 1 and isInfected[x+1][y] == 0:
                isInfected[x+1][y] = 2
                walls_to_add += 1
            if y > 0 and isInfected[x][y-1] == 0:
                isInfected[x][y-1] = 2
                walls_to_add += 1
            if y < cols - 1 and isInfected[x][y+1] == 0:
                isInfected[x][y+1] = 2
                walls_to_add += 1

        return walls_to_add

    def update_isInfected_grid(self, isInfected, region):
