from collections import deque

class Solution(object):
    def longestIncreasingPath(self, matrix):
        """
        :type matrix: List[List[int]]
        :rtype: int
        """
        if not matrix:
            return 0

        rows, cols = len(matrix), len(matrix[0])
        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]
        dp = [[0 for _ in range(cols)] for _ in range(rows)]

        queue = deque()

        # Initialize the queue with all starting points
        for i in range(rows):
            for j in range(cols):
                queue.append((i, j))

        while queue:
            row, col = queue.popleft()

            # Explore all four possible directions
            for dx, dy in directions:
                new_row, new_col = row + dx, col + dy

                # Check if the new position is valid and has a larger value
                if 0 <= new_row < rows and 0 <= new_col < cols and matrix[new_row][new_col] > matrix[row][col]:
                    # Update the DP table
                    dp[new_row][new_col] = max(dp[new_row][new_col], dp[row][col] + 1)

                    # Add the new position to the queue
                    queue.append((new_row, new_col))

        # Find the maximum value in the DP table
        return max(max(row) for row in dp)

