def countDigitOne(self, n):
    if n == 0:
        return 0

    # Initialize variables for dynamic programming
    dp = [0] * (n + 1)

    # Base case: there is one '1' at the beginning of numbers from 1 to 9
    dp[1] = 1

    # Fill the DP array
    for i in range(2, n + 1):
        # If the current digit is '0', it contributes to the number of '1's in the previous digits
        if i % 10 == 0:
            dp[i] = dp[i - 1]
        else:
            # Otherwise, it contributes to the number of '1's in the current and previous digits
            dp[i] = dp[i - 1] + (i // 10) * 10 + min(i % 10, 1)

    return dp[n]

