def findRedundantDirectedConnection(edges):
    # Create a dictionary to store the graph structure
    graph = defaultdict(list)

    # Initialize sets to keep track of visited nodes and cycles
    visited = set()
    cycle = set()

    # Iterate through each edge to build the graph
