            return False

        visited.add(node)

        # Recursively visit neighbors
        for neighbor in graph[node]:
            if neighbor != parent and dfs(neighbor, node):
                return True

        # If no cycle detected, mark node as part of a cycle
        cycle.add(node)
        return False

    # Find the first node with an incoming edge
    for u, v in edges:
        if v in graph:
