import sys

def dp(grid, i1, j1, i2, j2, memo):
    if i1 >= len(grid) or j1 >= len(grid[0]) or i2 >= len(grid) or j2 >= len(grid[0]):
        return -sys.maxsize

    if memo[i1][i2][j1][j2] != -1:
        return memo[i1][i2][j1][j2]

    res = 0
    # move from [i1, j1] to [i2, j2], and try all directions
    for di in range(-1, 2):
        for dj in range(-1, 2):
            res = max(res, dp(grid, i1 + di, j1 + dj, i2 + di, j2 + dj, memo))

    if i1 == i2 and j1 == j2:
        # if we end up at the same cell, we get two cherries
        res += grid[i1][j1]
    else:
        # otherwise, we get one cherry
        res += grid[i1][j1] + grid[i2][j2]

    memo[i1][i2][j1][j2] = res
    return res

class Solution(object):
    def cherryPickup(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: int
        """
        n = len(grid)
        memo = [[[[-1 for _ in range(n)] for _ in range(n)] for _ in range(n)] for _ in range(n)]
        return dp(grid, 0, 0, 0, 0, memo)

