class Solution(object):
    def nearestPalindromic(self, n):
        """
        :type n: str
        :rtype: str
        """
        # Edge case: single digit number
        if len(n) == 1:
            return str(int(n) - 1)

        # Edge case: number is already a palindrome
        if n == n[::-1]:
            return str(int(n) + 2)

        # Get the middle part of the number
        mid = n[len(n) // 2]

        # Check if the middle part is even or odd
        if len(n) % 2 == 0:
            # For even middle part, we need to check both cases: adding 1 and subtracting 1 from the middle part
            lower_palindrome = int(n[:len(n) // 2] + str(int(mid) - 1)) + int(str(int(mid) - 1)[::-1])
            upper_palindrome = int(n[:len(n) // 2] + str(int(mid) + 1)) + int(str(int(mid) + 1)[::-1])
        else:
            # For odd middle part, we need to check only the case where we add 1 to the middle part
            lower_palindrome = int(n[:len(n) // 2] + str(int(mid) - 1)) + int(str(int(mid) - 1)[::-1])
            upper_palindrome = int(n[:len(n) // 2] + str(int(mid) + 1)) + int(str(int(mid) + 1)[::-1])

        # Return the closest palindrome
        return min(lower_palindrome, upper_palindrome, key=lambda x: abs(int(x) - int(n)))

