from collections import deque

def bfs(beginWord, endWord, wordList):
    # Build adjacency list
    adj_list = defaultdict(set)
    for w in wordList:
        for i in range(len(w)):
            new_word = w[:i] + '*' + w[i+1:]
            adj_list[new_word].add(w)

    # BFS with queue
    q = deque([(beginWord, [beginWord])])
    visited = set([beginWord])
    while q:
        node, path = q.popleft()
        if node == endWord:
            return path
        for i in range(len(node)):
            new_word = node[:i] + '*' + node[i+1:]
            for neighbor in adj_list[new_word]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    q.append((neighbor, path + [neighbor]))

    return []

class Solution(object):
    def findLadders(self, beginWord, endWord, wordList):
        """
        :type beginWord: str
        :type endWord: str
        :type wordList: List[str]
        :rtype: List[List[str]]
        """
        # Check if endWord is not in wordList
        if endWord not in wordList:
            return []

        # Find all shortest paths from beginWord to endWord
        shortest_paths = bfs(beginWord, endWord, wordList)
        if not shortest_paths:
            return []

        # Generate all possible transformations from beginWord to endWord
        transformations = []
        for path in shortest_paths:
            transformations.append([])
            for i in range(len(path) - 1):
                new_word = path[i][:i] + '*' + path[i+1][i+1:]
                transformations[-1].append(new_word)

        # Find all possible transformations between each pair of transformations
        result = []
        for i in range(len(transformations) - 1):
            for j in range(i+1, len(transformations)):
                result.extend(find_transformations(transformations[i], transformations[j]))

        return result

