def countOfAtoms(formula):
    stack = [(defaultdict(int), 1)]
    i = 0

    while i < len(formula):
        c = formula[i]

        if c.isupper():
            start = i + 1
            while start < len(formula) and formula[start].islower():
                start += 1

            key = formula[i:start]
            stack[-1][key] += stack[-1][key] * int(formula[start:])

        elif c.isdigit():
            start = i
            while start < len(formula) and formula[start].isdigit():
                start += 1

            stack[-1][formula[i:start]] += int(formula[i:start])
            i = start - 1

        elif c == '(':
            stack.append((defaultdict(int), 1))
            i += 1

        elif c == ')':
            count, prev = stack.pop()
            for k, v in count.items():
                stack[-1][k] += v * prev

        i += 1

    result = ''

    for k, v in sorted(stack[0]):
        if v > 1:
            result += '{}{}'.format(k, v)
        else:
            result += k

