def findWords(board, words):
    if not board or not words:
        return []

    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    # Build Trie
    trie = {}
    for word in words:
        node = trie
        for char in word:
            if char not in node:
                node[char] = {}
            node = node[char]
        node['end'] = True

    def dfs(i, j, node, path, result):
        if 'end' in node:
            result.append(path)
            del node['end']

        for dx, dy in directions:
            nx, ny = i + dx, j + dy
            if 0 <= nx < len(board) and 0 <= ny < len(board[0]) and board[nx][ny] in node:
                tmp = board[nx][ny]
                board[nx][ny] = '#'  # Mark visited
                dfs(nx, ny, node[tmp], path + tmp, result)
                board[nx][ny] = tmp  # Backtrack

    result = []
    for i in range(len(board)):
        for j in range(len(board[0])):
            if board[i][j] in trie:
                dfs(i, j, trie[board[i][j]], board[i][j], result)

    return result

