class Solution:
    def candy(self, ratings: List[int]) -> int:
        # Initialize an array of length n with each element set to 1
        candies = [1]*len(ratings)

        # Iterate from left to right
        for i in range(1,len(ratings)):
            if ratings[i]>ratings[i-1]:
                # If the current rating is greater than the previous rating,
                # increment the number of candies for the current child by one
                candies[i] = candies[i-1]+1

        # Iterate from right to left
        for i in range(len(ratings)-2,-1,-1):
            if ratings[i]>ratings[i+1]:
                # If the current rating is greater than the next rating,
                # increment the number of candies for the current child by one,
                # but only if the candies for the next child are less than or equal to the current child's candies
                candies[i] = max(candies[i],candies[i+1]+1)

        # Return the sum of all elements in the candies array
        return sum(candies)

