        for i, j in zip(range(row, -1, -1), range(col, -1, -1)):
            if self.board[i][j]:
                return False

        # check right-bottom diagonal
        for i, j in zip(range(row, -1, -1), range(col, self.n)):
            if self.board[i][j]:
                return False

