    def solveNQueens(self, n):
        """
        :type n: int
        :rtype: List[List[str]]
        """
        res = []
        if n == 0:
            return res

        def is_valid(board, row, col):
            for i in range(row):
                if board[i][col] == 'Q':
                    return False

            i, j = row - 1, col - 1
            while i >= 0 and j >= 0:
                if board[i][j] == 'Q':
                    return False
                i -= 1
                j -= 1

            i, j = row - 1, col + 1
            while i >= 0 and j < n:
                if board[i][j] == 'Q':
                    return False
                i -= 1
                j += 1

            return True

        def backtrack(board, row):
            if row == n:
                res.append([''.join(i) for i in board])
                return

            for col in range(n):
                if not is_valid(board, row, col):
                    continue

                board[row][col] = 'Q'
                backtrack(board, row + 1)
                board[row][col] = '.'

        board = [['.' for _ in range(n)] for _ in range(n)]
        backtrack(board, 0)
        return res

